'use client';

import { useMemo } from 'react';
import { Badge } from '@/components/ui/badge';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { Button } from '@/components/ui/button';
import { MoreHorizontal, CheckCircle, XCircle, Clock, Loader2 } from 'lucide-react';
import { cn } from '@/lib/utils';
import { useFirebase, useCollection, useMemoFirebase } from '@/firebase';
import { collectionGroup, query, doc } from 'firebase/firestore';
import type { QuoteRequestWithId } from '@/lib/types';
import { updateDocumentNonBlocking } from '@/firebase/non-blocking-updates';


const statusStyles: { [key: string]: string } = {
  Approved: 'bg-green-100 text-green-800 border-green-200 dark:bg-green-900/50 dark:text-green-300 dark:border-green-800',
  'In Review': 'bg-yellow-100 text-yellow-800 border-yellow-200 dark:bg-yellow-900/50 dark:text-yellow-300 dark:border-yellow-800',
  Pending: 'bg-blue-100 text-blue-800 border-blue-200 dark:bg-blue-900/50 dark:text-blue-300 dark:border-blue-800',
  Rejected: 'bg-red-100 text-red-800 border-red-200 dark:bg-red-900/50 dark:text-red-300 dark:border-red-800',
  Completed: 'bg-gray-100 text-gray-800 border-gray-200 dark:bg-gray-900/50 dark:text-gray-300 dark:border-gray-800',
};


export default function AdminDashboardPage() {
  const { firestore } = useFirebase();

  const quoteRequestsQuery = useMemoFirebase(
    () => (firestore ? query(collectionGroup(firestore, 'quoteRequests')) : null),
    [firestore]
  );
  const { data: quoteRequests, isLoading } = useCollection<QuoteRequestWithId>(quoteRequestsQuery);

  const handleStatusChange = (customerId: string, quoteId: string, status: QuoteRequestWithId['status']) => {
    if (!firestore) return;
    const docRef = doc(firestore, 'customers', customerId, 'quoteRequests', quoteId);
    updateDocumentNonBlocking(docRef, { status });
  };


  return (
    <div className="container mx-auto">
      <header className="mb-8">
        <h1 className="text-4xl font-headline font-bold text-foreground">Admin Dashboard</h1>
        <p className="mt-2 text-lg text-muted-foreground">Manage incoming quote requests.</p>
      </header>
      <Card>
        <CardHeader>
          <CardTitle>Incoming Requests</CardTitle>
          <CardDescription>
            Review and manage all customer quote requests.
          </CardDescription>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <div className="flex justify-center items-center h-48">
              <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
          ) : (
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Customer</TableHead>
                <TableHead>Project Description</TableHead>
                <TableHead className="hidden sm:table-cell">Submitted</TableHead>
                <TableHead>Status</TableHead>
                <TableHead>
                  <span className="sr-only">Actions</span>
                </TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {quoteRequests && quoteRequests.map((request) => (
                <TableRow key={request.id}>
                  <TableCell>
                    <div className="font-medium">{request.customerName}</div>
                    <div className="text-sm text-muted-foreground">{request.customerEmail}</div>
                  </TableCell>
                  <TableCell>
                     <div className="font-medium">{request.projectDescription}</div>
                  </TableCell>
                  <TableCell className="hidden sm:table-cell">
                    {new Date(request.submittedDate).toLocaleDateString()}
                  </TableCell>
                  <TableCell>
                    <Badge variant="outline" className={cn('whitespace-nowrap', statusStyles[request.status])}>
                      {request.status}
                    </Badge>
                  </TableCell>
                  <TableCell>
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <Button aria-haspopup="true" size="icon" variant="ghost">
                          <MoreHorizontal className="h-4 w-4" />
                          <span className="sr-only">Toggle menu</span>
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuLabel>Actions</DropdownMenuLabel>
                        <DropdownMenuItem onClick={() => handleStatusChange(request.customerId, request.id, 'Approved')}>
                          <CheckCircle className="mr-2 h-4 w-4" />
                          Approve
                        </DropdownMenuItem>
                        <DropdownMenuItem onClick={() => handleStatusChange(request.customerId, request.id, 'Rejected')}>
                          <XCircle className="mr-2 h-4 w-4" />
                          Reject
                        </DropdownMenuItem>
                         <DropdownMenuItem onClick={() => handleStatusChange(request.customerId, request.id, 'In Review')}>
                          <Clock className="mr-2 h-4 w-4" />
                          Mark as In Review
                        </DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
          )}
        </CardContent>
      </Card>
    </div>
  );
}
